<template>
  <section>
    <Header class="py-4"></Header>
    <div class="container-fluid flex flex-col gap-6 py-6 px-2 md:flex-row">        
        <sidebar class="md:w-1/4 border shadow" v-on:setNavBar="updRightConten" v-on:crudStatus="updCrud"></sidebar>

        <div class="flex flex-1 flex-col w-full border shadow rounded-lg bg-white text-left py-4 p-8">          
          <div class="grid grid-cols-admin h-10 border-b-2 mb-2"> 
            <h2 class="text-2xl ">{{title}}</h2>
            <div class="flex">
               <button class="w-full text-center" v-show="crudvisible"  @click="showTable" ><i class="fa fa-arrow-left"></i></button>
               <button class="w-full text-center" v-show="!crudvisible" @click="refreshTable"><i class="fas fa-sync text-green-400"></i></button>
               <button class="w-full text-center" v-show="!crudvisible && !notCreate" @click="createRow"><i class="fa fa-plus text-green-400"></i></button>
            </div>
         </div>

          <!-- Table -->
          <admin-table 
            :actions="{show: true, edit: true, delete: true}" 
            :deleteCols="[]" 
            :rows="localData" 
            :editableColumns="editableColumns"
            v-on:editData="editRow" 
            v-on:deleteData="deleteRow"            
            v-on:cell-updated="handleCellUpdated"
            v-on:boolean-sort="handleBooleanSort"
            v-if="!crudvisible">
          </admin-table>    
          <!-- 
            @field-save="handleFieldSave" 
            @batch-save="handleBatchSave" 
            Load Cruds Form -->
          <dashboard v-if="crudvisible" :menu="activeMenu" :modeAction="mode" :objId="formInfo"></dashboard>
        </div>
    </div>
  </section>  
</template>

<script>
import Header from "@/components/Header.vue";
import AdminTable from '@/components/Admin/AdminTable';
import '@/assets/css/table.css'

// External services
import Authorization from "@/services/user/auth.service";
import Services from "@/services/index";

// Component
import Sidebar from '@/components/Admin/Sidebar.vue';
// Dashboard
import Dashboard from "@/views/Admin/Dashboard.vue";

export default {
  name: "Admin",  
  components: {
    Header,
    Sidebar,   
    AdminTable, 
    Dashboard,
  },
  data() {
    return {      
      title: '',
      mode: 'create',
      errMsg: '',
      formInfo: 0,      
      localData: [
        {
            name: 'Melia Varadero1',
            email: 'meliavaradero@melia.com',
            agent: 'Melia-Varadero',
        }
      ], 
      crudvisible: false,  
      editableColumns: false,  
      notCreate: false,    
      activeMenu: 'client',
      service: null,
      isLogged: false,
      // Datos originales sin filtrar para ordenamiento
      originalData: [],
      // Estado actual de ordenamiento
      currentSort: {
        column: null,
        state: 'all'
      }
    }
  },
  created() {
    // Validar si el usuario esta logueado
    this.title = (Authorization.validateRole(['ROLE_Agency', 'ROLE_Admin'])) ? 'Usuarios' : (Authorization.validateRole(['ROLE_Comercial'])) ? 'Polos' : 'Usuarios'
    this.isLogged = Authorization.isClientLogged()    
    this.activeMenu = (this.$route.params.CrudKey == undefined) ? 'client' : this.$route.params.CrudKey
    this.initCrud(this.activeMenu)    
  },
  methods: {
    initCrud(param) {      
      // Get List of the table      
      Services.init(param).then(d => {
        if('errors' in d) {
          console.log(d.errors)
        } else {
          // Guardar datos originales para ordenamiento
          this.originalData = [...d];
          this.localData = d;
        }
      })

      this.notCreate = (
        this.$route.params.CrudKey === 'marketplace_order' ||
        this.$route.params.CrudKey === 'marketplace_client'
      )
      
      this.crudvisible = false
      
    },
    updRightConten(text, view, items, isEditable = false, service = null) {
      this.title = text
      this.activeMenu = view
      
      // Verificar si las columnas deben ser editables
      this.editableColumns = isEditable
      this.service = service
      // Draw table data
      this.localData = (items) ? items : []    
    },    
    createRow() {
      
      // No muestro el formulario de editar en caso de booking
      if(this.$route.params.CrudKey !== 'booking')
      {
        this.mode = 'create'
        this.crudvisible = !this.crudvisible
        this.notCreate = !this.notCreate
      }      

    }, 
    editRow(rowData) {
      // Showing Form     
      this.crudvisible = !this.crudvisible          
      this.notCreate = (
        this.$route.params.CrudKey === 'marketplace_order' ||
        this.$route.params.CrudKey === 'marketplace_client'
      )
      this.mode = 'update'          
      this.formInfo = rowData.id
    },
    deleteRow(ids) {            
      Services.delete(this.activeMenu, ids).then(d => {
        // Actualizar datos originales después de eliminar
        this.originalData = [...d];
        
        // Si hay un ordenamiento activo para marketplace_item, aplicarlo usando el servicio
        if (this.currentSort.column && this.currentSort.state !== 'all' && this.activeMenu === 'marketplace_item') {
          this.applyBooleanSort(this.currentSort.column, this.currentSort.state);
        } else {
          this.localData = d;
        }
      })
    },
    refreshTable() {
      Services.init(this.activeMenu).then(d => {
        // Guardar datos originales para ordenamiento
        this.originalData = [...d];
        
        // Si hay un ordenamiento activo para marketplace_item, aplicarlo usando el servicio
        if (this.currentSort.column && this.currentSort.state !== 'all' && this.activeMenu === 'marketplace_item') {
          this.applyBooleanSort(this.currentSort.column, this.currentSort.state);
        } else {
          this.localData = d;
        }
      })
    },
    showTable() {      
      this.crudvisible = !this.crudvisible
      this.notCreate = (
        this.$route.params.CrudKey === 'marketplace_order' ||
        this.$route.params.CrudKey === 'marketplace_client'
      )

    },
    updCrud() {
      this.mode = 'create'
      this.crudvisible = false
      this.notCreate = (
        this.$route.params.CrudKey === 'marketplace_order' ||
        this.$route.params.CrudKey === 'marketplace_client'
      )

    },        
    handleCellUpdated(event) {      
      if(this.service) {
        this.service.fastUpdate(event.id, event.column, event.value)
      }
    },
    
    // Manejar eventos de ordenamiento booleano
    async handleBooleanSort(sortEvent) {
      const { column, state } = sortEvent;
      
      // Actualizar estado actual
      this.currentSort = { column, state };
      
      // Aplicar ordenamiento a los datos
      await this.applyBooleanSort(column, state);
    },
    
    // Aplicar ordenamiento booleano a los datos
    async applyBooleanSort(column, state) {
      // Si es marketplace_item, usar el servicio de búsqueda
      if (this.activeMenu === 'marketplace_item' && this.service && this.service.getList) {
        try {
          let filters = {};
          
          if (state === 'true') {
            filters[column] = true;
          } else if (state === 'false') {
            filters[column] = false;
          }
          // Si es 'all', no enviamos filtro
          
          const searchResults = await this.service.getList(filters);
          this.localData = searchResults;
          this.originalData = [...searchResults];
        } catch (error) {
          console.error('Error en búsqueda booleana:', error);
          // En caso de error, mostrar todos los datos
          this.refreshTable();
        }
      } else {
        // Para otros tipos de datos, usar filtrado local (fallback)
        const dataToSort = [...this.originalData];
        
        let filteredData;
        
        switch (state) {
          case 'true':
            filteredData = dataToSort.filter(row => row[column] === true);
            break;
          case 'false':
            filteredData = dataToSort.filter(row => row[column] === false);
            break;
          case 'all':
          default:
            filteredData = dataToSort;
            break;
        }
        
        this.localData = filteredData;
      }
    }
  }  
};
</script>

<style scoped>
section {
  min-height: 1000px;
}
</style>
